"""Generate Pine Script v6 stubs for all 20 short strategies."""
from __future__ import annotations

from pathlib import Path

from .strategies_short import SHORT_STRATEGIES

OUTPUT_DIR = Path(__file__).parent.parent / "TX-Short-Experiments" / "pine"

_PINE_HEADER = """//@version=6
// Auto-generated by tx/experiments/pine_generator_short.py
// Instrument: TAIFEX:MXF1! (MTX 小台指期)
strategy("{title}", overlay=true, default_qty_type=strategy.fixed, default_qty_value=1,
         currency=currency.TWD, commission_type=strategy.commission.cash_per_order, commission_value=100)

sl_pts  = input.int(30, "SL Points", minval=5, group="Risk")
tp_pts  = input.int(60, "TP Points", minval=5, group="Risk")
use_day   = input.bool(true,  "日盤 (08:45-13:45)", group="Session")
use_night = input.bool(true,  "夜盤 (15:00-05:00)", group="Session")

t = time("30", "0845-1345", "Asia/Taipei")
n = time("30", "1500-0500", "Asia/Taipei")
in_session = (use_day and not na(t)) or (use_night and not na(n))

rsi        = ta.rsi(close, 14)
[macd, sig, hist] = ta.macd(close, 12, 26, 9)
[bb_upper, bb_mid, bb_lower] = ta.bb(close, 20, 2)
ema9       = ta.ema(close, 9)
ema21      = ta.ema(close, 21)
ema55      = ta.ema(close, 55)
atr        = ta.atr(14)
stoch_k    = ta.sma(ta.stoch(close, high, low, 14), 3)
stoch_d    = ta.sma(stoch_k, 3)
don_high   = ta.highest(high[1], 20)
don_low    = ta.lowest(low[1], 20)
cci        = ta.cci(close, 20)
willr      = ta.wpr(14)
bb_pct     = (close - bb_lower) / (bb_upper - bb_lower)

"""

_SHORT_ENTRY_STUBS: dict[str, str] = {
    "S01": "entry_signal = ta.crossunder(rsi, 70) and rsi > 45",
    "S02": "entry_signal = ta.crossunder(macd, sig) and macd > 0",
    "S03": "entry_signal = hist[2] > hist[1] and hist[1] > hist and hist[2] > 0",
    "S04": "entry_signal = ta.crossunder(stoch_k, stoch_d) and stoch_k > 75",
    "S05": "entry_signal = ta.crossover(willr, -20)",
    "S06": "entry_signal = ta.crossunder(cci, 100)",
    "S07": "entry_signal = ta.crossunder(rsi, 50) and ema21 < ema55",
    "S08": "entry_signal = ta.crossunder(ema9, ema21) and close < ema55",
    "S09": "entry_signal = math.abs(close - ema55) < atr * 0.4 and ema21 < ema55 and rsi >= 35 and rsi <= 60",
    "S10": "[st_val, st_dir] = ta.supertrend(3.0, 10)\nentry_signal = ta.crossunder(close, st_val)",
    "S11": "entry_signal = close < don_low and rsi < 50",
    "S12": "bb_width = (bb_upper - bb_lower) / bb_mid\nsqueeze = bb_width < ta.percentile_linear_interpolation(bb_width, 100, 20)\nentry_signal = squeeze[1] and ta.crossunder(close, bb_lower)",
    "S13": "low20 = ta.lowest(close[1], 20)\nentry_signal = close < low20 - atr * 0.3 and rsi < 50",
    "S14": "entry_signal = bb_pct >= 0.95 and rsi > 55 and rsi < rsi[3]",
    "S15": "entry_signal = bb_pct > 0.80 and ta.crossunder(rsi, 70)",
    "S16": "body = math.abs(close - open)\nupper_wick = high - math.max(open, close)\nlower_wick = math.min(open, close) - low\nentry_signal = upper_wick > body * 2 and lower_wick < body * 0.5 and body > 0 and rsi > 45",
    "S17": "entry_signal = close < open and close[1] > open[1] and open >= close[1] and close <= open[1] and rsi > 40",
    "S18": "// Requires RSI bearish divergence signal\nentry_signal = false  // replace with your divergence signal",
    "S19": "first_bar = (hour == 8 and minute == 45)\nvar float orb_low = na\nif first_bar\n    orb_low := low\nentry_signal = not na(t) and close < orb_low and rsi < 50 and not first_bar",
    "S20": "entry_signal = not na(n) and (rsi - rsi[3]) < -2 and close < ema21 and hist < 0 and rsi > 35 and rsi < 55",
}

_RISK_BLOCK = """
// ── Entry & Exit ───────────────────────────────────────
if entry_signal and in_session
    strategy.entry("{code}_SE", strategy.short)

if strategy.position_size < 0
    strategy.exit("{code}_SE_X", from_entry="{code}_SE",
                  profit=tp_pts, loss=sl_pts)
"""


def generate_all(output_dir: Path = OUTPUT_DIR):
    output_dir.mkdir(parents=True, exist_ok=True)
    all_scripts: list[tuple[str, str, str]] = []

    for code, (_, name, _) in SHORT_STRATEGIES.items():
        stub = _SHORT_ENTRY_STUBS.get(code, f"entry_signal = false  // {code} not implemented")
        body = (
            _PINE_HEADER.replace("{title}", f"TX {code} {name}")
            + stub + "\n"
            + _RISK_BLOCK.replace("{code}", code)
        )
        safe_name = name.replace(" ", "_").replace("/", "_")
        path = output_dir / f"{code}_{safe_name}.pine"
        path.write_text(body, encoding="utf-8")
        all_scripts.append((code, name, stub))

    _generate_combined(output_dir, all_scripts)
    print(f"Pine scripts → {output_dir}  ({len(all_scripts)} files + 1 combined)")


def _generate_combined(output_dir: Path, scripts: list[tuple[str, str, str]]):
    options = ",".join(f'"{c} {n}"' for c, n, _ in scripts)
    header = f"""//@version=6
strategy("TX All Short Strategies", overlay=true, default_qty_type=strategy.fixed, default_qty_value=1,
         currency=currency.TWD, commission_type=strategy.commission.cash_per_order, commission_value=100)

strategy_id = input.string("{scripts[0][0]} {scripts[0][1]}", "Strategy", options=[{options}], group="Strategy")
sl_pts  = input.int(30, "SL Points", minval=5, group="Risk")
tp_pts  = input.int(60, "TP Points", minval=5, group="Risk")
use_day   = input.bool(true,  "日盤", group="Session")
use_night = input.bool(true,  "夜盤", group="Session")

t = time("30", "0845-1345", "Asia/Taipei")
n = time("30", "1500-0500", "Asia/Taipei")
in_session = (use_day and not na(t)) or (use_night and not na(n))

rsi        = ta.rsi(close, 14)
[macd, sig, hist] = ta.macd(close, 12, 26, 9)
[bb_upper, bb_mid, bb_lower] = ta.bb(close, 20, 2)
ema9       = ta.ema(close, 9)
ema21      = ta.ema(close, 21)
ema55      = ta.ema(close, 55)
atr        = ta.atr(14)
stoch_k    = ta.sma(ta.stoch(close, high, low, 14), 3)
stoch_d    = ta.sma(stoch_k, 3)
don_high   = ta.highest(high[1], 20)
don_low    = ta.lowest(low[1], 20)
cci        = ta.cci(close, 20)
willr      = ta.wpr(14)
bb_pct     = (close - bb_lower) / (bb_upper - bb_lower)

entry_signal = false

"""
    cases = ""
    for code, name, stub in scripts:
        cases += f'if strategy_id == "{code} {name}"\n'
        for line in stub.split("\n"):
            cases += f"    {line}\n"
        cases += "\n"

    footer = """
if entry_signal and in_session
    strategy.entry("SE", strategy.short)
if strategy.position_size < 0
    strategy.exit("SE_X", from_entry="SE", profit=tp_pts, loss=sl_pts)
"""
    combined = header + cases + footer
    (output_dir / "ALL_Short_Strategies.pine").write_text(combined, encoding="utf-8")
